from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """Generate a natural language sentence from a list of triples."""
    if not triples:
        return ""

    # Group triples by subject
    subject_triples = {}
    for t in triples:
        if t.subject not in subject_triples:
            subject_triples[t.subject] = []
        subject_triples[t.subject].append(t)

    # Get the primary subject (most common subject in triples)
    subject_counts = {s: len(ts) for s, ts in subject_triples.items()}
    primary_subject = max(subject_counts, key=subject_counts.get)

    # Collect information by predicate type for the primary subject
    creators = []
    series_info = None
    nationality = None
    other_info = []

    for t in subject_triples.get(primary_subject, []):
        if t.predicate == "creator":
            creators.append(t.object)
        elif t.predicate == "series":
            series_info = t.object
        elif t.predicate == "nationality":
            nationality = t.object
        else:
            other_info.append(t)

    # Normalize nationality (e.g., "Americans" -> "American")
    if nationality:
        if nationality.endswith("s") and nationality != "United States":
            nationality = nationality[:-1]

    # Build the main clause
    parts = []

    # Start with character name and series info
    if series_info:
        parts.append(f"{primary_subject}, which appears in the series {series_info}")
    else:
        parts.append(primary_subject)

    # Add creator information
    if creators:
        if len(creators) == 1:
            parts.append(f"was created by {creators[0]}")
        else:
            creators_str = " and ".join(creators)
            parts.append(f"was created by {creators_str}")

    # Add nationality
    if nationality:
        parts.append(f"and is {nationality}")

    # Add other information from primary subject
    for t in other_info:
        if t.predicate == "fullName":
            parts.append(f"with the full name {t.object}")
        elif t.predicate == "alternativeName":
            parts.append(f"also known as {t.object}")
        elif t.predicate == "award":
            parts.append(f"who received the {t.object}")
        elif t.predicate == "voice":
            parts.append(f"voiced by {t.object}")
        elif t.predicate == "starring":
            parts.append(f"starring {t.object}")
        elif t.predicate == "firstAired":
            parts.append(f"which first aired on {t.object}")
        elif t.predicate == "lastAired":
            parts.append(f"which last aired on {t.object}")
        elif t.predicate == "birthPlace":
            parts.append(f"with birth place {t.object}")
        elif t.predicate == "child":
            parts.append(f"with a child named {t.object}")

    # Add information from other subjects using relative clauses
    for subject, tlist in subject_triples.items():
        if subject == primary_subject:
            continue
        for t in tlist:
            if t.predicate == "birthPlace":
                # Find if this subject is mentioned in creators
                if subject in creators:
                    parts.append(f", {subject} was born in {t.object}")
            elif t.predicate == "starring":
                # Add starring info for series
                if subject == series_info:
                    parts.append(f"which stars {t.object}")

    # Build final sentence
    if len(parts) == 0:
        return primary_subject

    # Join with appropriate connectors
    if len(parts) == 1:
        return parts[0] + "."
    else:
        result = parts[0]
        for i, part in enumerate(parts[1:], 1):
            if part.startswith("which") or part.startswith("with") or part.startswith("voiced") or part.startswith("starring"):
                result += f", {part}"
            elif part.startswith("and"):
                result += f", {part}"
            else:
                result += f", {part}"
        return result + "."

# EVOLVE-BLOCK-END

